# 方法1：兼容 DataFrame 写法
def log_transform_df(X):
    X = X.copy()
    for col in X.columns:
        if X[col].min() >= 0:
            X[col] = np.log1p(X[col])
    return X

log_tf = FunctionTransformer(log_transform_df)

# 方法2：如果确定输入是 numpy array
def log_transform_np(X):
    return np.log1p(X)

log_tf = FunctionTransformer(log_transform_np)
